import{c as n,S as h,j as i,m as o}from"./chunks/framework.8aa1YH_s.js";const e=JSON.parse('{"title":"Đề mẫu Luyện thi (HSA / TSA / THPT)","description":"","frontmatter":{},"headers":[],"relativePath":"admin/de-mau-luyen-thi.md","filePath":"admin/de-mau-luyen-thi.md","lastUpdated":0}'),g={name:"admin/de-mau-luyen-thi.md"};function r(a,t,c,l,s,d){return h(),i("div",null,[...t[0]||(t[0]=[o('<h1 id="đe-mau-luyen-thi-hsa-tsa-thpt" tabindex="-1">Đề mẫu Luyện thi (HSA / TSA / THPT) <a class="header-anchor" href="#đe-mau-luyen-thi-hsa-tsa-thpt" aria-label="Permalink to “Đề mẫu Luyện thi (HSA / TSA / THPT)”">​</a></h1><p><strong>Đường dẫn:</strong> <code>https://lamsonedutech.vn/admin/question/examDgnl</code></p><p>Đề mẫu Luyện thi là <strong>đề thi mô phỏng kỳ thi thật</strong>: ĐGNL (HSA - Đại học Quốc gia Hà Nội), ĐGTD (TSA - Đại học Bách khoa Hà Nội), TNTHPT (kỳ thi tốt nghiệp). Các đề này dùng đúng cấu trúc, đếm ngược thời gian, phân điểm theo từng phần — học viên làm để <strong>tập đi tập lại tâm lý phòng thi</strong>.</p><h2 id="khi-nao-dung" tabindex="-1">Khi nào dùng <a class="header-anchor" href="#khi-nao-dung" aria-label="Permalink to “Khi nào dùng”">​</a></h2><ul><li>Học viên đang ôn luyện thi HSA/TSA/THPT và cần làm thử đề full.</li><li>Trung tâm tổ chức <strong>thi thử định kỳ</strong> cho cả lớp.</li><li>Đo trình độ trước/sau một giai đoạn ôn luyện.</li><li>Tạo <strong>bộ đề mẫu</strong> dán nhãn năm thi (vd &quot;Đề mẫu HSA 2026 - Đợt 1&quot;) cho học viên luyện liên tục.</li></ul><h2 id="danh-sach-đe-mau" tabindex="-1">Danh sách đề mẫu <a class="header-anchor" href="#danh-sach-đe-mau" aria-label="Permalink to “Danh sách đề mẫu”">​</a></h2><p>Cột chính:</p><table tabindex="0"><thead><tr><th>Cột</th><th>Ý nghĩa</th></tr></thead><tbody><tr><td>Tên đề</td><td>Vd &quot;Đề mẫu HSA 2026 - Đợt 1&quot;</td></tr><tr><td>Loại kỳ thi</td><td>ĐGNL / ĐGTD / TNTHPT</td></tr><tr><td>Tổng số câu</td><td>Tổng câu hỏi của đề</td></tr><tr><td>Tổng thời gian</td><td>Tổng phút</td></tr><tr><td>Năm thi</td><td>Vd 2026</td></tr><tr><td>Người tạo</td><td></td></tr><tr><td>Trạng thái</td><td>Công khai / Nháp / Ẩn</td></tr></tbody></table><h3 id="bo-loc" tabindex="-1">Bộ lọc <a class="header-anchor" href="#bo-loc" aria-label="Permalink to “Bộ lọc”">​</a></h3><ul><li>Theo <strong>Loại kỳ thi</strong> (ĐGNL/ĐGTD/TNTHPT).</li><li>Theo <strong>Năm thi</strong>.</li><li>Theo <strong>Trạng thái</strong>.</li><li>Tìm kiếm theo <strong>Tên đề</strong>.</li></ul><h2 id="cau-truc-cac-ky-thi" tabindex="-1">Cấu trúc các kỳ thi <a class="header-anchor" href="#cau-truc-cac-ky-thi" aria-label="Permalink to “Cấu trúc các kỳ thi”">​</a></h2><p>Hệ thống đóng khung sẵn cấu trúc của từng kỳ thi. Khi tạo đề, bạn chỉ cần điền câu hỏi vào đúng vị trí từng phần.</p><h3 id="đgnl-hsa-đai-hoc-quoc-gia-ha-noi" tabindex="-1">ĐGNL - HSA (Đại học Quốc gia Hà Nội) <a class="header-anchor" href="#đgnl-hsa-đai-hoc-quoc-gia-ha-noi" aria-label="Permalink to “ĐGNL - HSA (Đại học Quốc gia Hà Nội)”">​</a></h3><p>Đề HSA gồm <strong>3 phần</strong>, <strong>150 câu</strong>, <strong>195 phút</strong>:</p><table tabindex="0"><thead><tr><th>Phần</th><th>Tên phần</th><th>Số câu</th><th>Thời gian</th><th>Nội dung</th></tr></thead><tbody><tr><td>1</td><td><strong>Tư duy định lượng</strong></td><td>50</td><td>75 phút</td><td>Toán học, suy luận logic số liệu</td></tr><tr><td>2</td><td><strong>Tư duy định tính</strong></td><td>50</td><td>60 phút</td><td>Ngữ văn, đọc hiểu, tiếng Việt</td></tr><tr><td>3</td><td><strong>Khoa học</strong></td><td>50</td><td>60 phút</td><td>Lý, Hóa, Sinh, Sử, Địa (chọn theo tổ hợp)</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Phần Khoa học <strong>chia tiếp</strong> thành các môn lựa chọn. Học viên có thể chọn tổ hợp Khoa học tự nhiên (Lý-Hóa-Sinh) hoặc Khoa học xã hội (Sử-Địa-GDCD). Khi cấu hình đề, có thể tạo nhiều <strong>phiên bản phần 3</strong> để học viên chọn.</p></div><p>Đặc điểm:</p><ul><li>Mỗi phần <strong>đếm giờ riêng</strong> — hết giờ phần này tự chuyển sang phần kế.</li><li><strong>Không trở lại phần trước</strong> khi đã sang phần mới.</li><li>Trong từng phần, học viên có thể di chuyển giữa các câu.</li><li>Dạng câu: Trắc nghiệm 4 đáp án, <strong>Điền số / Điền đáp án ngắn</strong>.</li></ul><h3 id="đgtd-tsa-đai-hoc-bach-khoa-ha-noi" tabindex="-1">ĐGTD - TSA (Đại học Bách khoa Hà Nội) <a class="header-anchor" href="#đgtd-tsa-đai-hoc-bach-khoa-ha-noi" aria-label="Permalink to “ĐGTD - TSA (Đại học Bách khoa Hà Nội)”">​</a></h3><p>Đề TSA gồm <strong>3 phần chính</strong>:</p><table tabindex="0"><thead><tr><th>Phần</th><th>Tên phần</th><th>Số câu</th><th>Thời gian</th><th>Nội dung</th></tr></thead><tbody><tr><td>1</td><td><strong>Tư duy Toán học</strong></td><td>40</td><td>60 phút</td><td>Toán logic, đại số, hình học, xác suất</td></tr><tr><td>2</td><td><strong>Tư duy Đọc hiểu</strong></td><td>20</td><td>30 phút</td><td>Đọc hiểu văn bản khoa học, kỹ thuật</td></tr><tr><td>3</td><td><strong>Tư duy Khoa học / Giải quyết vấn đề</strong></td><td>40</td><td>60 phút</td><td>Lý, Hóa, Sinh kết hợp, kỹ năng giải quyết vấn đề</td></tr></tbody></table><p>Đặc điểm:</p><ul><li><strong>Tổng: 100 câu, 150 phút</strong>.</li><li>Đếm <strong>giờ tổng</strong> (không tách phần như HSA), học viên tự phân bổ thời gian.</li><li>Có thể <strong>đánh dấu câu</strong> và quay lại trước khi nộp.</li><li>Nhiều câu dạng <strong>Đúng - Sai nhiều ý</strong>, <strong>Trả lời ngắn</strong>.</li></ul><h3 id="tnthpt-tot-nghiep-thpt" tabindex="-1">TNTHPT (Tốt nghiệp THPT) <a class="header-anchor" href="#tnthpt-tot-nghiep-thpt" aria-label="Permalink to “TNTHPT (Tốt nghiệp THPT)”">​</a></h3><p>TNTHPT cấu hình theo <strong>từng môn riêng biệt</strong>, không gộp thành 1 đề duy nhất:</p><table tabindex="0"><thead><tr><th>Môn</th><th>Số câu</th><th>Thời gian</th><th>Dạng câu chủ yếu</th></tr></thead><tbody><tr><td><strong>Toán</strong></td><td>40</td><td>90 phút</td><td>Trắc nghiệm 4 lựa chọn + Trả lời ngắn (điền số)</td></tr><tr><td><strong>Ngữ văn</strong></td><td>Tự luận</td><td>120 phút</td><td>Đề tự luận (đọc hiểu + NLXH + NLVH)</td></tr><tr><td><strong>Tiếng Anh</strong></td><td>40</td><td>60 phút</td><td>Trắc nghiệm + đọc hiểu (trích đoạn)</td></tr><tr><td><strong>Vật lí</strong></td><td>40</td><td>50 phút</td><td>Trắc nghiệm + Đúng-Sai + Trả lời ngắn</td></tr><tr><td><strong>Hóa học</strong></td><td>40</td><td>50 phút</td><td>Trắc nghiệm + Đúng-Sai + Trả lời ngắn</td></tr><tr><td><strong>Sinh học</strong></td><td>40</td><td>50 phút</td><td>Trắc nghiệm + Đúng-Sai + Trả lời ngắn</td></tr><tr><td><strong>Lịch sử</strong></td><td>40</td><td>50 phút</td><td>Trắc nghiệm + Đúng-Sai</td></tr><tr><td><strong>Địa lí</strong></td><td>40</td><td>50 phút</td><td>Trắc nghiệm + Đúng-Sai + Trả lời ngắn</td></tr><tr><td><strong>GDKT&amp;PL</strong></td><td>40</td><td>50 phút</td><td>Trắc nghiệm + Đúng-Sai</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Mỗi môn TNTHPT là <strong>1 đề riêng</strong>. Nếu muốn tạo &quot;Gói thi thử TNTHPT đợt 1&quot; gồm nhiều môn, hãy tạo các đề riêng rồi gộp thành 1 <a href="./bo-de-thi">Bộ đề thi</a>.</p></div><h2 id="tao-moi-đe-mau" tabindex="-1">Tạo mới đề mẫu <a class="header-anchor" href="#tao-moi-đe-mau" aria-label="Permalink to “Tạo mới đề mẫu”">​</a></h2><ol><li>Bấm <strong>Thêm mới</strong>.</li><li>Chọn <strong>Loại kỳ thi</strong>: ĐGNL / ĐGTD / TNTHPT. <ul><li>Nếu TNTHPT, chọn tiếp <strong>Môn thi</strong>.</li></ul></li><li>Khai báo thông tin chung: <ul><li><strong>Tên đề</strong> (vd &quot;Đề mẫu HSA 2026 - Đợt 1&quot;).</li><li><strong>Năm thi</strong>.</li><li><strong>Mô tả</strong> (tùy chọn).</li><li><strong>Hướng dẫn làm bài</strong> (hiển thị trước khi học viên bấm &quot;Bắt đầu&quot;).</li></ul></li><li>Hệ thống sinh sẵn các <strong>phần</strong> theo cấu trúc đã định ở mục trên. Bạn không tự thêm/xóa phần (để giữ đúng cấu trúc đề thi thực tế).</li><li>Thêm câu hỏi vào từng phần (xem mục kế tiếp).</li><li>Cấu hình <strong>luật làm bài</strong>: <ul><li><strong>Đếm giờ theo phần</strong> (mặc định ON với HSA) hoặc <strong>đếm giờ tổng</strong> (TSA, TNTHPT).</li><li><strong>Cho phép xem lại câu trước</strong> trong cùng phần.</li><li><strong>Trộn câu</strong> giữa các lượt làm.</li><li><strong>Trộn đáp án</strong> trong từng câu.</li><li><strong>Tự nộp khi hết giờ</strong>.</li><li><strong>Số lần làm tối đa</strong> (0 = không giới hạn).</li><li><strong>Hiển thị đáp án sau khi nộp</strong>: Có / Không / Có kèm lời giải.</li></ul></li><li>(Tùy chọn) <strong>Lịch mở đề</strong>: thời điểm bắt đầu/kết thúc.</li><li>Bấm <strong>Lưu</strong>.</li></ol><h2 id="them-cau-hoi-cho-tung-phan" tabindex="-1">Thêm câu hỏi cho từng phần <a class="header-anchor" href="#them-cau-hoi-cho-tung-phan" aria-label="Permalink to “Thêm câu hỏi cho từng phần”">​</a></h2><ol><li>Trong chi tiết đề, mở <strong>tab của phần</strong> muốn thêm câu (vd &quot;Phần 1 - Tư duy định lượng&quot;).</li><li>Bấm <strong>Thêm câu hỏi</strong>.</li><li>Có 2 chế độ: <ul><li><strong>Chọn cố định</strong>: lọc câu từ <a href="./danh-muc-cau-hoi">Danh mục câu hỏi</a> → tick chọn → thêm.</li><li><strong>Theo tiêu chí</strong>: chọn 1 <a href="./tieu-chi-de-thi">Tiêu chí đề thi</a> phù hợp với phần đó → hệ thống random.</li></ul></li><li>Sau khi thêm: <ul><li>Kéo-thả để sắp xếp.</li><li>Sửa điểm từng câu.</li><li>Xóa câu lỗi.</li></ul></li><li>Kiểm tra <strong>tổng số câu của phần</strong> phải khớp với cấu trúc kỳ thi (vd HSA Phần 1 phải đúng 50 câu).</li><li>Bấm <strong>Lưu</strong>.</li></ol><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Nếu <strong>số câu thực tế khác cấu trúc chuẩn</strong> (vd HSA Phần 1 chỉ có 48 câu thay vì 50), hệ thống cảnh báo &quot;Đề chưa đủ câu&quot;. Đề vẫn lưu được dạng Nháp nhưng <strong>không công khai được</strong> cho đến khi đủ.</p></div><h2 id="sua-đe-mau" tabindex="-1">Sửa đề mẫu <a class="header-anchor" href="#sua-đe-mau" aria-label="Permalink to “Sửa đề mẫu”">​</a></h2><ol><li>Tại danh sách, bấm <strong>Sửa</strong>.</li><li>Cập nhật thông tin, câu hỏi, cấu hình.</li><li>Bấm <strong>Lưu</strong>.</li></ol><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Sửa đề khi đã có học viên làm sẽ ảnh hưởng kết quả cũ. Khuyến nghị <strong>tạo phiên bản mới</strong> (Nhân bản đề + tăng số đợt) và ẩn đề cũ.</p></div><h2 id="xoa-đe-mau" tabindex="-1">Xóa đề mẫu <a class="header-anchor" href="#xoa-đe-mau" aria-label="Permalink to “Xóa đề mẫu”">​</a></h2><ol><li>Tại danh sách, bấm <strong>Xóa</strong>.</li><li>Xác nhận.</li></ol><div class="danger custom-block"><p class="custom-block-title custom-block-title-default">DANGER</p><p>Đề đã có lượt làm chỉ bị <strong>ẩn</strong> chứ không xóa hẳn — để giữ điểm cũ của học viên. Liên hệ quản trị nếu cần xóa hẳn dữ liệu lịch sử.</p></div><h2 id="nhan-ban-đe" tabindex="-1">Nhân bản đề <a class="header-anchor" href="#nhan-ban-đe" aria-label="Permalink to “Nhân bản đề”">​</a></h2><p>Khi cần tạo đợt thi thử kế tiếp với cấu trúc giống đợt trước:</p><ol><li>Bấm <strong>Nhân bản</strong> trên dòng đề gốc.</li><li>Bản sao tự tạo với hậu tố &quot;(Bản sao)&quot;.</li><li>Đổi <strong>Tên đề</strong> thành đợt mới (vd &quot;Đề mẫu HSA 2026 - Đợt 2&quot;).</li><li>Vào từng phần, <strong>thay câu hỏi</strong> sang bộ câu mới.</li><li>Lưu.</li></ol><h2 id="gan-đe-cho-hoc-vien-lop-khoa" tabindex="-1">Gán đề cho học viên / lớp / khóa <a class="header-anchor" href="#gan-đe-cho-hoc-vien-lop-khoa" aria-label="Permalink to “Gán đề cho học viên / lớp / khóa”">​</a></h2><p>Sau khi tạo đề:</p><ol><li>Mở chi tiết đề.</li><li>Vào tab <strong>Gán đề</strong> (hoặc <strong>Phân phối</strong>).</li><li>Chọn đối tượng: <ul><li><strong>Khóa học</strong>: học viên đã mua khóa đều thấy.</li><li><strong>Lớp học</strong>: chỉ học viên trong lớp.</li><li><strong>Theo nhóm</strong>: chọn nhóm học viên cụ thể.</li><li><strong>Toàn bộ</strong>: công khai cho mọi học viên có quyền HSA/TSA/THPT.</li></ul></li><li>Lưu.</li></ol><h2 id="xem-ket-qua-thong-ke" tabindex="-1">Xem kết quả &amp; thống kê <a class="header-anchor" href="#xem-ket-qua-thong-ke" aria-label="Permalink to “Xem kết quả &amp; thống kê”">​</a></h2><ol><li>Mở chi tiết đề → tab <strong>Kết quả</strong>.</li><li>Bảng hiển thị: <ul><li>Học viên, lần làm, <strong>điểm từng phần</strong>, <strong>tổng điểm</strong>, thời gian.</li><li><strong>Quy đổi điểm</strong> sang thang chuẩn (HSA: thang 150; TSA: thang 100; TNTHPT: thang 10).</li></ul></li><li>Bấm vào dòng để xem chi tiết bài làm + câu sai.</li><li><strong>Xuất Excel</strong> danh sách kết quả.</li><li><strong>Biểu đồ phân bố điểm</strong>: xem nhanh độ khó của đề.</li></ol><p>→ Thống kê toàn hệ thống ở <a href="./thong-ke">Thống kê</a>.</p><h2 id="xuat-đe-ra-file-word-pdf" tabindex="-1">Xuất đề ra file Word / PDF <a class="header-anchor" href="#xuat-đe-ra-file-word-pdf" aria-label="Permalink to “Xuất đề ra file Word / PDF”">​</a></h2><ol><li>Tại chi tiết đề, bấm <strong>Xuất đề</strong>.</li><li>Chọn định dạng: <ul><li><strong>Word</strong> (có thể chỉnh sửa lại).</li><li><strong>PDF có đáp án</strong>.</li><li><strong>PDF không đáp án</strong> (để in cho học viên).</li></ul></li><li>Tải file về.</li></ol><p>→ Hữu ích khi tổ chức <strong>thi thử trực tiếp tại trung tâm</strong> trên giấy.</p><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Tôi tạo đề HSA nhưng phần 3 muốn cho học viên chọn KHTN hoặc KHXH - làm sao?</strong> → Hiện tại hệ thống cho phép tạo <strong>2 phiên bản đề HSA</strong> (1 cho KHTN, 1 cho KHXH). Khi giao bài, học viên chọn đúng phiên bản phù hợp. Hoặc trong cùng đề, tạo Phần 3 dạng nhánh: học viên chọn 1 trong 2 cụm câu.</p><p><strong>TNTHPT thi 4 môn, tôi có tạo được 1 đề gộp 4 môn không?</strong> → Không. Mỗi môn TNTHPT là 1 đề riêng. Hãy tạo 4 đề rồi gộp vào 1 <a href="./bo-de-thi">Bộ đề thi</a> &quot;Thi thử TNTHPT đợt 1&quot;.</p><p><strong>Đề HSA phải đúng 150 câu - lỡ tôi nhập thừa/thiếu thì sao?</strong> → Hệ thống cảnh báo &quot;Đề chưa đủ câu / vượt số câu&quot;. Bạn không công khai được cho học viên nếu số câu sai cấu trúc. Hãy kiểm tra từng phần.</p><p><strong>Học viên báo &quot;hết giờ phần 1 mà chưa làm xong, không quay lại được&quot;.</strong> → Đó là <strong>đúng cấu trúc HSA</strong>. Khi đã sang phần 2, không quay lại phần 1. Hãy hướng dẫn học viên phân bổ thời gian.</p><p><strong>Có hiển thị đáp án ngay sau khi nộp không?</strong> → Tùy cấu hình. Khuyến nghị <strong>chỉ hiển thị đáp án</strong> sau khi học viên đã làm xong + tắt chia sẻ → tránh lộ đề. Có thể cho xem <strong>lời giải chi tiết</strong> cũng được, tùy mục tiêu.</p><p><strong>Đề thi này dùng cùng câu với đề ôn khóa học - có trùng không?</strong> → Có thể trùng. Nếu muốn tách biệt, hãy đánh dấu các câu chuyên dụng cho HSA/TSA/THPT (gắn tag), khi tạo tiêu chí thì lọc theo tag để không trùng với đề ôn.</p><p><strong>Tôi muốn cho thi thử miễn phí cho tất cả học viên (kể cả chưa mua khóa).</strong> → Trong tab <strong>Gán đề</strong>, chọn <strong>Công khai cho mọi học viên</strong>. Lưu ý: vẫn yêu cầu học viên có tài khoản đăng nhập.</p><p><strong>Quy đổi điểm HSA 150 → điểm xét tuyển có chính xác không?</strong> → Hệ thống quy đổi theo công thức <strong>chuẩn của ĐHQGHN</strong> công bố. Tuy nhiên điểm chính thức chỉ có khi thi thật. Đề mẫu chỉ dùng để <strong>tham khảo, định hướng</strong>.</p>',59)])])}const p=n(g,[["render",r]]);export{e as __pageData,p as default};
